import { describe, test, expect, beforeEach, afterEach } from 'bun:test';
import fs from 'fs';
import path from 'path';
import { ModManager } from '../mod/manager.js';

describe('ModManager', () => {
    const testDir = path.resolve(process.cwd(), '.gnosis-test-tmp');
    const origCwd = process.cwd();

    beforeEach(() => {
        fs.mkdirSync(testDir, { recursive: true });
        process.chdir(testDir);
    });

    afterEach(() => {
        process.chdir(origCwd);
        fs.rmSync(testDir, { recursive: true, force: true });
    });

    test('init creates gnosis.mod file', () => {
        const manager = new ModManager();
        manager.init('github.com/test/module');

        const modPath = path.resolve(testDir, 'gnosis.mod');
        expect(fs.existsSync(modPath)).toBe(true);

        const content = fs.readFileSync(modPath, 'utf-8');
        expect(content).toContain('module github.com/test/module');
        expect(content).toContain('gnosis 0.1.0');
    });

    test('init throws if gnosis.mod already exists', () => {
        const manager = new ModManager();
        manager.init('github.com/test/module');
        expect(() => manager.init('github.com/test/another')).toThrow('already exists');
    });

    test('parse reads module name and version', () => {
        const manager = new ModManager();
        manager.init('github.com/test/module');

        const modFile = manager.parse();
        expect(modFile.module).toBe('github.com/test/module');
        expect(modFile.gnosisVersion).toBe('0.1.0');
        expect(modFile.requires).toEqual([]);
    });

    test('parse throws if no gnosis.mod exists', () => {
        const manager = new ModManager();
        expect(() => manager.parse()).toThrow('No gnosis.mod found');
    });

    test('parse reads single-line require', () => {
        fs.writeFileSync(
            path.resolve(testDir, 'gnosis.mod'),
            `module github.com/test/mod\n\ngnosis 0.1.0\n\nrequire github.com/dep/one v1.2.3\n`,
            'utf-8'
        );

        const manager = new ModManager();
        const modFile = manager.parse();
        expect(modFile.requires).toHaveLength(1);
        expect(modFile.requires[0].path).toBe('github.com/dep/one');
        expect(modFile.requires[0].version).toBe('v1.2.3');
    });

    test('parse reads block require', () => {
        fs.writeFileSync(
            path.resolve(testDir, 'gnosis.mod'),
            [
                'module github.com/test/mod',
                '',
                'gnosis 0.1.0',
                '',
                'require (',
                '  github.com/dep/one v1.0.0',
                '  github.com/dep/two v2.0.0',
                ')',
            ].join('\n'),
            'utf-8'
        );

        const manager = new ModManager();
        const modFile = manager.parse();
        expect(modFile.requires).toHaveLength(2);
        expect(modFile.requires[0].path).toBe('github.com/dep/one');
        expect(modFile.requires[1].path).toBe('github.com/dep/two');
    });

    test('parse ignores comments', () => {
        fs.writeFileSync(
            path.resolve(testDir, 'gnosis.mod'),
            [
                '// This is a comment',
                'module github.com/test/mod',
                '// Another comment',
                'gnosis 0.1.0',
            ].join('\n'),
            'utf-8'
        );

        const manager = new ModManager();
        const modFile = manager.parse();
        expect(modFile.module).toBe('github.com/test/mod');
    });
});
